#include "BSOpeningDirector.h"
#include "Components/StaticMeshComponent.h"
#include "Components/TextRenderComponent.h"
#include "NiagaraComponent.h"
ABSOpeningDirector::ABSOpeningDirector(){PrimaryActorTick.bCanEverTick=false;Root=CreateDefaultSubobject<USceneComponent>(TEXT("Root"));SetRootComponent(Root);HeroWeapon=CreateDefaultSubobject<UStaticMeshComponent>(TEXT("HeroWeapon"));HeroWeapon->SetupAttachment(Root);Sparks=CreateDefaultSubobject<UNiagaraComponent>(TEXT("Sparks"));Sparks->SetupAttachment(Root);Sparks->SetAutoActivate(false);Fire=CreateDefaultSubobject<UNiagaraComponent>(TEXT("Fire"));Fire->SetupAttachment(Root);Fire->SetAutoActivate(false);Smoke=CreateDefaultSubobject<UNiagaraComponent>(TEXT("Smoke"));Smoke->SetupAttachment(Root);Smoke->SetAutoActivate(false);Caption=CreateDefaultSubobject<UTextRenderComponent>(TEXT("Caption"));Caption->SetupAttachment(Root);Caption->SetHorizontalAlignment(EHTA_Center);Caption->SetWorldSize(42);}
void ABSOpeningDirector::SetOpeningMoment(float T){Caption->SetText(FText::GetEmpty());Sparks->Deactivate();Fire->Deactivate();Smoke->Deactivate();if(T<3)Caption->SetText(NSLOCTEXT("BLACKSmith","Soul","魂を打て。"));else if(T<7){Fire->Activate(true);Sparks->Activate(true);}else if(T<12){Fire->Activate(true);Sparks->Activate(true);Smoke->Activate(true);Caption->SetText(NSLOCTEXT("BLACKSmith","Unique","世界に一本だけの武器を。"));}else if(T<16){Fire->Activate(true);Sparks->Activate(true);Caption->SetText(NSLOCTEXT("BLACKSmith","Grade","BLACK Smith"));}else Caption->SetText(NSLOCTEXT("BLACKSmith","Tagline","勝者を決めるのは、剣ではない。鍛冶師だ。"));}
